// StreamingText.tsx — renders tokens as they arrive, with a blinking cursor
import { useEffect, useRef, useState } from "react";

type StreamStatus = "idle" | "streaming" | "done" | "error";

interface StreamingTextProps {
  /** Fetch and stream from this endpoint on mount (or when it changes) */
  streamUrl:   string;
  requestBody: object;
}

export function StreamingText({ streamUrl, requestBody }: StreamingTextProps) {
  const [text,   setText]   = useState("");
  const [status, setStatus] = useState<StreamStatus>("idle");
  const [error,  setError]  = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  useEffect(() => {
    const controller = new AbortController();
    abortRef.current = controller;

    (async () => {
      setStatus("streaming");
      setText("");
      try {
        const res = await fetch(streamUrl, {
          method:  "POST",
          headers: { "Content-Type": "application/json" },
          body:    JSON.stringify(requestBody),
          signal:  controller.signal,
        });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);

        const reader  = res.body!.getReader();
        const decoder = new TextDecoder();

        while (true) {
          const { value, done } = await reader.read();
          if (done) break;
          const chunk = decoder.decode(value, { stream: true });
          // Parse SSE lines: "data: <json>\n\n"
          for (const line of chunk.split("\n")) {
            if (!line.startsWith("data: ")) continue;
            const payload = JSON.parse(line.slice(6));
            if (payload.type === "TEXT_MESSAGE_DELTA") {
              setText(t => t + payload.delta);
            }
          }
        }
        setStatus("done");
      } catch (err: unknown) {
        if ((err as Error).name === "AbortError") {
          setStatus("idle");
        } else {
          setError((err as Error).message);
          setStatus("error");
        }
      }
    })();

    return () => controller.abort();   // cleanup on unmount or re-run
  }, [streamUrl, JSON.stringify(requestBody)]);

  if (status === "error") {
    return (
      <div className="rounded-xl border border-red-800 bg-red-950 p-3 text-sm text-red-300">
        {error}
        <button onClick={() => setStatus("idle")} className="ml-3 underline text-red-400">Retry</button>
      </div>
    );
  }

  return (
    <p className="text-slate-200 text-sm leading-relaxed whitespace-pre-wrap">
      {text}
      {status === "streaming" && (
        <span className="ml-0.5 inline-block w-0.5 h-4 bg-indigo-400 align-middle animate-pulse" />
      )}
    </p>
  );
}

// PartialJsonCard.tsx — renders a card from streaming partial JSON args
// Pattern: accumulate raw partial JSON string, try to parse on each delta,
// show skeleton while parsing fails, swap to real card when it succeeds.

interface CardData {
  title:    string;
  subtitle: string;
  value:    number;
  trend:    "up" | "down" | "flat";
}

interface PartialJsonCardProps {
  /** Raw JSON string that may be incomplete (during streaming) */
  rawJson:  string;
  isStreaming: boolean;
}

export function PartialJsonCard({ rawJson, isStreaming }: PartialJsonCardProps) {
  // Attempt to parse on each render; fall back to skeleton on parse failure
  let data: CardData | null = null;
  try {
    data = JSON.parse(rawJson);
  } catch {
    // Still accumulating — show skeleton
  }

  if (!data) {
    return <CardSkeleton />;
  }

  const trendColor =
    data.trend === "up"   ? "text-green-400" :
    data.trend === "down" ? "text-red-400"   : "text-slate-400";

  return (
    <div className={`rounded-xl border border-slate-700 p-4 transition-opacity ${isStreaming ? "opacity-70" : "opacity-100"}`}>
      <p className="text-xs text-slate-500">{data.subtitle}</p>
      <p className="text-slate-100 font-semibold text-lg mt-0.5">{data.title}</p>
      <p className={`text-2xl font-bold mt-1 ${trendColor}`}>
        {data.value.toLocaleString()}
        <span className="ml-1 text-sm">{data.trend === "up" ? "▲" : data.trend === "down" ? "▼" : "—"}</span>
      </p>
    </div>
  );
}

function CardSkeleton() {
  return (
    <div className="rounded-xl border border-slate-700 p-4 animate-pulse">
      <div className="h-3 w-24 rounded bg-slate-700 mb-2" />
      <div className="h-5 w-40 rounded bg-slate-700 mb-3" />
      <div className="h-8 w-20 rounded bg-slate-700" />
    </div>
  );
}

// AbortControls.tsx — Stop button wired to an AbortController
import { useCallback, useRef, useState } from "react";

export function useStreamWithAbort(url: string) {
  const [text,      setText]      = useState("");
  const [isRunning, setIsRunning] = useState(false);
  const controllerRef = useRef<AbortController | null>(null);

  const start = useCallback(async (body: object) => {
    // Cancel any in-flight request before starting a new one
    controllerRef.current?.abort();
    const controller = new AbortController();
    controllerRef.current = controller;

    setIsRunning(true);
    setText("");

    try {
      const res = await fetch(url, {
        method: "POST", body: JSON.stringify(body),
        headers: { "Content-Type": "application/json" },
        signal: controller.signal,
      });
      const reader  = res.body!.getReader();
      const decoder = new TextDecoder();
      while (true) {
        const { value, done } = await reader.read();
        if (done) break;
        const chunk = decoder.decode(value, { stream: true });
        for (const line of chunk.split("\n")) {
          if (line.startsWith("data: ")) {
            const e = JSON.parse(line.slice(6));
            if (e.type === "TEXT_MESSAGE_DELTA") setText(t => t + e.delta);
          }
        }
      }
    } catch (e: unknown) {
      if ((e as Error).name !== "AbortError") throw e;
    } finally {
      setIsRunning(false);
    }
  }, [url]);

  const stop = useCallback(() => {
    controllerRef.current?.abort();
  }, []);

  return { text, isRunning, start, stop };
}

