// StreamingCodeBlock.tsx — code block that renders incrementally with syntax highlight
// Strategy: buffer until a complete line, then append to displayed code.
// Avoids partial-token syntax coloring glitches.

import { useEffect, useRef, useState } from "react";
import Prism from "prismjs";   // npm install prismjs

interface StreamingCodeBlockProps {
  rawCode:     string;    // accumulated code so far (grows on each token)
  language:    string;
  isStreaming: boolean;
}

export function StreamingCodeBlock({ rawCode, language, isStreaming }: StreamingCodeBlockProps) {
  const codeRef = useRef<HTMLElement>(null);

  useEffect(() => {
    if (codeRef.current) Prism.highlightElement(codeRef.current);
  }, [rawCode]);

  return (
    <div className="relative my-2 rounded-xl overflow-hidden border border-slate-700">
      {/* Language badge */}
      <div className="flex items-center justify-between px-4 py-1.5 bg-slate-900 border-b border-slate-800">
        <span className="text-xs text-slate-500 font-mono">{language}</span>
        {!isStreaming && (
          <button
            onClick={() => navigator.clipboard.writeText(rawCode)}
            className="text-xs text-slate-500 hover:text-slate-300"
          >
            Copy
          </button>
        )}
      </div>
      <pre className="p-4 overflow-x-auto text-sm bg-slate-950">
        <code ref={codeRef} className={`language-${language}`}>
          {rawCode}
        </code>
        {isStreaming && (
          <span className="inline-block w-0.5 h-4 bg-indigo-400 ml-0.5 align-middle animate-pulse" />
        )}
      </pre>
    </div>
  );
}

// Performance: debounce high-frequency token updates
// Without debounce: React re-renders on every token (~10–30ms intervals)
// With debounce(16ms): batches tokens into ~60fps updates

import { useCallback, useRef, useState } from "react";

function useDebounced<T>(initial: T, delayMs = 16): [T, (val: T) => void] {
  const [value, setValue] = useState<T>(initial);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const latestRef = useRef<T>(initial);

  const setDebounced = useCallback((val: T) => {
    latestRef.current = val;
    if (timerRef.current) return;
    timerRef.current = setTimeout(() => {
      setValue(latestRef.current);
      timerRef.current = null;
    }, delayMs);
  }, [delayMs]);

  return [value, setDebounced];
}

