// StreamingText.test.tsx
import { render, screen, act } from "@testing-library/react";
import { StreamingText }       from "./StreamingText";

// Mock fetch to return a fake SSE stream
function makeSseStream(events: string[]): Response {
  const encoder = new TextEncoder();
  const stream  = new ReadableStream({
    start(controller) {
      for (const evt of events) {
        controller.enqueue(encoder.encode(evt));
      }
      controller.close();
    },
  });
  return new Response(stream, { status: 200 });
}

test("renders streamed text incrementally", async () => {
  global.fetch = vi.fn().mockResolvedValue(
    makeSseStream([
      "data: {\"type\":\"TEXT_MESSAGE_DELTA\",\"delta\":\"Hello\"}\n\n",
      "data: {\"type\":\"TEXT_MESSAGE_DELTA\",\"delta\":\" world\"}\n\n",
    ])
  );

  render(<StreamingText streamUrl="/api/chat" requestBody={{ messages: [] }} />);

  // Should eventually show the full text
  expect(await screen.findByText(/Hello world/)).toBeInTheDocument();
});

test("shows cursor while streaming", async () => {
  global.fetch = vi.fn().mockImplementation(() => new Promise(() => {}));  // never resolves
  const { container } = render(
    <StreamingText streamUrl="/api/chat" requestBody={{ messages: [] }} />
  );
  // Cursor appears while request is in-flight
  expect(container.querySelector(".animate-pulse")).toBeInTheDocument();
});
